SourceCode.Declaration:
/// <summary>
/// This class is an extension of AssetTable table.
/// </summary>
[ExtensionOf(tableStr(AssetTable))]
internal final class ETGAssetTable_Extension
{
}

Method.Source:
/// <summary>
/// Assigning the value of CapexApprovalId from PurchLine.
/// </summary>
/// <param name = "_skipCreateBooks">Boolean.</param>
public void insert(boolean _skipCreateBooks)
{
    if(this.PurchLineRecId != 0 && AssetParameters::find().ETGCapexApprovalIdFeature == NoYes::Yes)
    {
        PurchLine purchLine;

        select firstonly ETGCapexApprovalId from purchLine
            where purchLine.RecId            == this.PurchLineRecId
            &&    purchLine.CreateFixedAsset == NoYes::Yes;

        this.ETGCapexApprovalId = purchLine.ETGCapexApprovalId;
    }
    next insert(_skipCreateBooks);
}
